import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(n, edges) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    const reverseAdj = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        reverseAdj[v].push([u, w]);
    }

    // dist[node][used]: min cost to reach node with used flips
    const dist = Array.from({ length: n }, () => [Infinity, Infinity]);
    dist[0][0] = 0;

    const pq = new MinPriorityQueue({ priority: (x) => x[0] });
    pq.enqueue([0, 0, 0]); // [cost, node, used]

    while (!pq.isEmpty()) {
        const [currentCost, u, used] = pq.dequeue().element;
        if (u === n - 1) {
            return currentCost;
        }
        if (currentCost > dist[u][used]) {
            continue;
        }

        // Normal edges
        for (const [v, w] of adj[u]) {
            const newCost = currentCost + w;
            if (newCost < dist[v][used]) {
                dist[v][used] = newCost;
                pq.enqueue([newCost, v, used]);
            }
        }

        // Flip an incoming edge if not used yet
        if (used === 0) {
            for (const [v, w] of reverseAdj[u]) {
                const newCost = currentCost + 2 * w;
                if (newCost < dist[v][1]) {
                    dist[v][1] = newCost;
                    pq.enqueue([newCost, v, 1]);
                }
            }
        }
    }

    const result = Math.min(dist[n - 1][0], dist[n - 1][1]);
    return result === Infinity ? -1 : result;
}

